    "logging": {
      "coverage": "gaps",
      "gaps": [
        "No logging of queue depth or backlog size — operators cannot see the queue growing",
        "No logging of message age (time-in-queue) — cannot detect processing delays",
        "No logging of duplicate message detection — silent re-processing is invisible",
        "No logging of batch processing duration — cannot correlate with visibility timeout issues"
